// n8n Code Node - Spacchetta base64 photos e documents
// Mantiene tutti i campi originali, estrae mimetype e base64 pulito

const items = $input.all();

return items.map(item => {
  const inputData = item.json;

  // Clona tutti i campi originali
  const output = { ...inputData };

  // === PROCESSA PHOTOS ===
  if (Array.isArray(inputData.photos)) {
    output.photos = inputData.photos.map(photoBase64 => {
      if (typeof photoBase64 === 'string' && photoBase64.includes(',')) {
        // Split: "data:image/jpeg;base64,/9j/4AAQ..." -> ["data:image/jpeg;base64", "/9j/4AAQ..."]
        const [header, data] = photoBase64.split(',');

        // Estrai mimetype da "data:image/jpeg;base64"
        const mimetype = header.split(':')[1]?.split(';')[0] || 'image/jpeg';

        return {
          mimetype: mimetype,
          data: data  // Solo base64 pulito senza header
        };
      }

      // Se già è un oggetto, ritorna così com'è
      return photoBase64;
    });
  }

  // === PROCESSA DOCUMENTS ===
  if (Array.isArray(inputData.documents)) {
    output.documents = inputData.documents.map(doc => {
      // Se il documento ha già la struttura con "data" field
      if (doc.data && typeof doc.data === 'string' && doc.data.includes(',')) {
        const [header, data] = doc.data.split(',');
        const mimetype = header.split(':')[1]?.split(';')[0] || doc.type || 'application/pdf';

        return {
          name: doc.name,
          size: doc.size,
          mimetype: mimetype,
          data: data  // Solo base64 pulito
        };
      }

      // Se è direttamente una stringa base64
      if (typeof doc === 'string' && doc.includes(',')) {
        const [header, data] = doc.split(',');
        const mimetype = header.split(':')[1]?.split(';')[0] || 'application/pdf';

        return {
          mimetype: mimetype,
          data: data
        };
      }

      // Se già è formattato correttamente, ritorna così
      return doc;
    });
  }

  return { json: output };
});

// NODO: DPF (Dynamic Payload Factory) - MULTI-MEDIA VERSION
// VERSIONE: 3.0 - Supporto per array photos[] e documents[]
// OBIETTIVO: Assemblare il payload finale per Gemini con tutti i media inline

// --- 1. Estrazione degli Input ---
const item = $input.first().json;

// Input obbligatori
const systemInstruction = item.SystemInstruction;
const prompt = item.Prompt;
const modelChoiceUrl = item.ModelChoice;
const GeminiKey = item.GeminiKey;

// Input opzionali
const useGrounding = item.grounding === true;

// Array di media (già processati dal nodo precedente)
const photos = item.photos || [];
const documents = item.documents || [];

// Validazione input essenziali
if (!systemInstruction || !prompt || !modelChoiceUrl) {
    throw new Error('DPF Error: Input essenziali mancanti (SystemInstruction, Prompt, o ModelChoice).');
}

// --- 2. Costruzione della Sezione "contents" ---
const contentsParts = [{ "text": prompt }];

// === AGGIUNGI TUTTE LE FOTO ===
if (Array.isArray(photos) && photos.length > 0) {
    photos.forEach(photo => {
        if (photo.data && photo.mimetype) {
            contentsParts.push({
                "inline_data": {
                    "mime_type": photo.mimetype,
                    "data": photo.data
                }
            });
        }
    });
    console.log(`DPF: Aggiunte ${photos.length} foto al payload`);
}

// === AGGIUNGI TUTTI I DOCUMENTI ===
if (Array.isArray(documents) && documents.length > 0) {
    documents.forEach(doc => {
        if (doc.data && doc.mimetype) {
            contentsParts.push({
                "inline_data": {
                    "mime_type": doc.mimetype,
                    "data": doc.data
                }
            });
        }
    });
    console.log(`DPF: Aggiunti ${documents.length} documenti al payload`);
}

// --- 3. Costruzione del Payload Finale ---
let finalPayload = {
    "system_instruction": {
        "parts": [
            { "text": systemInstruction }
        ]
    },
    "contents": [
        {
            "role": "user",
            "parts": contentsParts
        }
    ],
    "generation_config": {
        "thinkingConfig": {
            "thinkingBudget": -1
        },
        "response_mime_type": "application/json"
    }
};

// --- 4. Configurazione Grounding (opzionale) ---
if (useGrounding) {
    finalPayload.tools = [
        {
            "google_search_retrieval": {}
        }
    ];
}

// --- 5. Output Finale (SOLO payload per Gemini) ---
const outputItem = {
    finalApiUrl: modelChoiceUrl,
    geminiApiCallPayload: finalPayload,
    GeminiKey: GeminiKey
};

// Logging per debug
console.log(`DPF: Payload preparato per: ${modelChoiceUrl}`);
console.log(`DPF: Grounding: ${useGrounding}`);
console.log(`DPF: Total media parts: ${contentsParts.length - 1}`); // -1 per il text prompt

return [{
    json: outputItem
}];

// Trasforma services array in quantity_service con service_id composito
const item = $input.first().json;

const vat = item.vat;
const services = item.services || [];

const quantityService = services.map(service => ({
  service_id: `${vat}-${service.callback_data}`,
  quantity: service.quantity
}));

return [{
  json: {
    quantity_service: quantityService
  }
}];

// NODO: Brutal Force Parser V7 - Proactive Sanitization Edition

// OBIETTIVO: Parser JSON robusto per output LLM con sistema di correzione
//            proattiva a cascata. Elimina la dipendenza dai messaggi di errore
//            specifici attraverso sanificazione preventiva intelligente.
//
// ARCHITETTURA: Logica bifasica con pipeline di sanificazione ottimizzata
//               Fase 1: Tentativo parsing diretto (ottimistico)
//               Fase 2: Sanificazione proattiva + retry (resiliente)
//
// OUTPUT: Oggetto JSON parsato (successo) o oggetto errore strutturato (fallimento)
// ==============================================================================

// --- FUNZIONI DI SANIFICAZIONE PROATTIVA ---

/**
 * Chiude parentesi graffe, quadre e virgolette non bilanciate
 * PRIORITÀ: MASSIMA - Garantisce integrità strutturale per operazioni successive
 */
function closeBracketsQuotes(str) {
    let cleaned = str;

    // Conteggio parentesi graffe
    const openBraces = (str.match(/{/g) || []).length;
    const closeBraces = (str.match(/}/g) || []).length;

    // Conteggio parentesi quadre
    const openBrackets = (str.match(/\[/g) || []).length;
    const closeBrackets = (str.match(/]/g) || []).length;

    // Chiusura intelligente: rispetta l'ordine di annidamento
    if (openBraces > closeBraces) {
        const missing = openBraces - closeBraces;
        cleaned += '}'.repeat(missing);
        console.log(`REPAIR APPLIED: Closed ${missing} unclosed brace(s).`);
    }

    if (openBrackets > closeBrackets) {
        const missing = openBrackets - closeBrackets;
        cleaned += ']'.repeat(missing);
        console.log(`REPAIR APPLIED: Closed ${missing} unclosed bracket(s).`);
    }

    // Gestione virgolette: conta solo quelle non escapate usando lookbehind negativo
    const unescapedQuotes = (str.match(/(?<!\\)"/g) || []).length;
    if (unescapedQuotes % 2 !== 0) {
        cleaned += '"';
        console.log("REPAIR APPLIED: Closed unclosed quote.");
    }

    return cleaned;
}

/**
 * Rimuove virgole trailing prima di } o ]
 * Errore comune: {"key":"value",} o [1,2,3,]
 */
function removeTrailingCommas(str) {
    const cleaned = str.replace(/,(\s*[}\]])/g, '$1');
    if (cleaned !== str) {
        console.log("REPAIR APPLIED: Removed trailing comma(s).");
    }
    return cleaned;
}

/**
 * Aggiunge virgole mancanti tra elementi consecutivi
 * Pattern gestiti:
 * - Stringhe consecutive: "a" "b" → "a","b"
 * - Oggetti consecutivi: }{  → },{
 * - Array consecutivi: ][  → ],[
 * - Proprietà oggetto: "key":"value" "key2" → "key":"value","key2"
 */
function fixMissingCommas(str) {
    let cleaned = str;

    // Virgola tra stringhe consecutive separate da newline o spazi
    cleaned = cleaned.replace(/"\s*\n\s*"/g, '",\n"');

    // Virgola tra oggetti consecutivi
    cleaned = cleaned.replace(/}(\s*){/g, '},\n{');

    // Virgola tra array consecutivi
    cleaned = cleaned.replace(/](\s*)\[/g, '],\n[');

    // Virgola tra proprietà di oggetti (pattern più conservativo)
    cleaned = cleaned.replace(/("\s*:\s*(?:"[^"]*"|[^,}\s]+))\s+"/g, '$1,"');

    if (cleaned !== str) {
        console.log("REPAIR APPLIED: Fixed missing comma(s).");
    }

    return cleaned;
}

/**
 * Pipeline di sanificazione completa con tracking delle operazioni
 * ORDINE OTTIMIZZATO: Struttura → Sintassi → Separatori
 * Questo ordine garantisce che le operazioni successive lavorino su JSON "completo"
 */
function sanitizeJsonString(str) {
    let result = str;
    const repairs = [];  // Traccia operazioni applicate per analytics

    // FASE 1: Completamento strutturale (massima priorità)
    const beforeClose = result;
    result = closeBracketsQuotes(result);
    if (result !== beforeClose) repairs.push("STRUCTURAL_CLOSURE");

    // FASE 2: Pulizia virgole trailing (ora su struttura completa)
    const beforeTrailing = result;
    result = removeTrailingCommas(result);
    if (result !== beforeTrailing) repairs.push("TRAILING_COMMA_REMOVAL");

    // FASE 3: Aggiunta virgole mancanti (ultima operazione)
    const beforeMissing = result;
    result = fixMissingCommas(result);
    if (result !== beforeMissing) repairs.push("MISSING_COMMA_INSERTION");

    // Log strutturato per analytics
    if (repairs.length > 0) {
        console.log(`SANITIZATION_PIPELINE: Applied [${repairs.join(' → ')}]`);
    }

    return result;
}

// --- FUNZIONE DI PARSING A DUE FASI ---

/**
 * Parser proattivo con strategia ottimistica + resiliente
 * Elimina completamente la dipendenza dai messaggi di errore specifici
 */
function proactiveJsonParse(jsonString) {
    // FASE 1: Tentativo diretto (percorso veloce per JSON già validi)
    try {
        const result = JSON.parse(jsonString);
        console.log("Phase 1 SUCCESS: Direct parsing succeeded.");
        return result;
    } catch (directError) {
        console.log(`Phase 1 failed: ${directError.message}. Attempting proactive sanitization...`);
    }

    // FASE 2: Sanificazione proattiva + Retry (percorso resiliente)
    try {
        const sanitized = sanitizeJsonString(jsonString);
        const parsed = JSON.parse(sanitized);
        console.log("Phase 2 SUCCESS: Parsing succeeded after sanitization.");
        return parsed;
    } catch (sanitizedError) {
        // Entrambe le fasi sono fallite - restituisce errore dettagliato
        throw new Error(
            `Parser Error: Impossibile riparare il JSON. ` +
            `Dettaglio: ${sanitizedError.message}`
        );
    }
}

// --- LOGICA PRINCIPALE DEL NODO ---

let stringToParse = '';  // Variabile per tracking in caso di errore

try {
    // --- ESTRAZIONE INPUT DA GEMINI API RESPONSE ---
    const rawString = $input.first().json.candidates[0].content.parts[0].text;

    // Validazione presenza e tipo
    if (!rawString || typeof rawString !== 'string' || rawString.trim() === '') {
        stringToParse = rawString || "Input vuoto";
        throw new Error("La stringa di input dall'AI è vuota o non valida.");
    }

    // --- PREPROCESSING: RIMOZIONE MARKDOWN CODE BLOCKS ---
    // Gestisce sia `````` come delimitatori
let cleanedString = rawString

    .replace(/^```(?:json)?\s*/, '') 
    .replace(/\s*```$/, '');        

    // --- ESTRAZIONE OGGETTO JSON PRINCIPALE ---
    // Cerca il primo { e l'ultimo } per isolare l'oggetto JSON
    const firstBrace = cleanedString.indexOf('{');
    const lastBrace = cleanedString.lastIndexOf('}');

    // Validazione presenza struttura JSON
    if (firstBrace === -1 || lastBrace === -1 || lastBrace < firstBrace) {
        stringToParse = cleanedString;
        throw new Error("Nessun oggetto JSON valido trovato nella stringa.");
    }

    // Estrazione substring contenente solo il JSON
    stringToParse = cleanedString.substring(firstBrace, lastBrace + 1);

    // --- PARSING PROATTIVO BIFASICO ---
    const parsedJson = proactiveJsonParse(stringToParse);

    // --- PERCORSO DI SUCCESSO ---
    // Restituisce il JSON parsato sulla via principale (uscita verde)
return [{
    json: {
        project: parsedJson
    }
}];

} catch (error) {
    // --- PERCORSO DI FALLIMENTO ---
    // Costruisce oggetto di errore strutturato invece di far fallire il nodo
    // Questo permette al workflow di gestire il fallimento tramite Livello 3 (LLM riparatore)
    console.error(`Parser ha fallito. Messaggio: ${error.message}`);
    console.error(`Stringa problematica salvata per fallback repair.`);

    return [{
        json: {
            error: error.message,
            Prompt: stringToParse  // Salva la stringa per il tentativo di riparazione LLM
        }
    }];
}

// ==============================================================================
// NOTE DI IMPLEMENTAZIONE:
// 
// 1. CONFIGURAZIONE NODO N8N:
//    - Mode: "Run Once for All Items"
//    - Language: JavaScript
//    - Continue On Fail: false (gestito internamente dal codice)
//
// 2. NODO SUCCESSIVO CONSIGLIATO:
//    Un "IF" node che controlla la presenza del campo "error" nell'output
//    - Se presente: instrada verso Livello 3 (LLM riparatore + MongoDB retry logic)
//    - Se assente: continua il workflow normale
//
// 3. LOGGING E ANALYTICS:
//    Tutti i console.log() sono visibili nei log di esecuzione n8n
//    Considera l'aggiunta di un nodo MongoDB logger per aggregare metriche:
//    - Frequenza operazioni di repair
//    - Tasso successo Fase 1 vs Fase 2
//    - Pattern di errori ricorrenti
//
// 4. EVOLUZIONE FUTURA:
//    Per aggiungere nuove correzioni, semplicemente:
//    a) Crea una nuova funzione fixNuovoErrore()
//    b) Aggiungila alla pipeline in sanitizeJsonString()
//    c) Aggiungi console.log() per tracking
//
// ==============================================================================

// NODO: Project Data Integration & Placeholder Replacement
// Sostituisce placeholder LLM con dati reali e arricchisce metadata

const item = $input.first().json;

// === 1. ESTRAI DATI REALI ===
const customer = item.customer;
const ownerData = item.owner_data;
const operatorId = item.operator_id;

// Trova operatore che ha creato il preventivo
const operator = ownerData.operators.find(op => op.OperatorChatID?.toString() === operatorId);
const operatorName = operator?.OperatorName || "Operatore Sconosciuto";

// Trova il task legato a questo VAT e operatore per estrarre invite_token
const taskIndex = customer.tasks?.findIndex(task => 
  task.linked_vat_id === ownerData.vat_number && 
  task.linked_operator_id === operatorId
);

const customerTask = customer.tasks?.[taskIndex];
const inviteToken = customerTask?.invite_token || null;

// Genera Project ID basato su invite_token se disponibile
let projectId;
if (inviteToken) {
  projectId = `${inviteToken}`;
} else {
  projectId = `${item.project.meta.quote_id.replace('QT-', '')}`;
}

// === 2. DATI REALI CLIENTE ===
const realCustomerData = {
  name: `${customer.firstName} ${customer.lastName}`.trim(),
  email: customer.email,
  phone: customer.phone || "N/A",
  company: customer.company || "Privato",
  address: customer.address ? 
    `${customer.address.street}, ${customer.address.zip} ${customer.address.city} (${customer.address.province})` : 
    "N/A"
};

// === 3. FUNZIONE DI SOSTITUZIONE PLACEHOLDER ===
function replacePlaceholders(text, realData) {
  if (typeof text !== 'string') return text;

  return text
    .replace(/<name>.*?<\/name>/g, realData.name)
    .replace(/<email>.*?<\/email>/g, realData.email)
    .replace(/<company>.*?<\/company>/g, realData.company)
    .replace(/<phone>.*?<\/phone>/g, realData.phone)
    .replace(/\{customer_name\}/g, realData.name)
    .replace(/\{customer_email\}/g, realData.email)
    .replace(/\{customer_company\}/g, realData.company)
    .replace(/\{customer_phone\}/g, realData.phone)
    .replace(/Alberto Trinaier/g, realData.name)
    .replace(/TrinAi Srl/g, realData.company)
    .replace(/info@trinai\.it/g, realData.email);
}

// === 4. APPLICA SOSTITUZIONE RICORSIVA ===
function deepReplacePlaceholders(obj, realData) {
  if (typeof obj === 'string') {
    return replacePlaceholders(obj, realData);
  } else if (Array.isArray(obj)) {
    return obj.map(item => deepReplacePlaceholders(item, realData));
  } else if (obj !== null && typeof obj === 'object') {
    const newObj = {};
    for (const key in obj) {
      newObj[key] = deepReplacePlaceholders(obj[key], realData);
    }
    return newObj;
  }
  return obj;
}

// === 5. CLONA E PROCESSA IL PROJECT ===
let enrichedProject = JSON.parse(JSON.stringify(item.project));

// Sostituisci tutti i placeholder nel project
enrichedProject = deepReplacePlaceholders(enrichedProject, realCustomerData);

// === 6. ARRICCHISCI METADATA ===
enrichedProject.meta.project_id = projectId;
enrichedProject.meta.invite_token = inviteToken;
enrichedProject.meta.created_at = new Date().toISOString();
enrichedProject.meta.created_by_operator = operatorName;
enrichedProject.meta.created_by_operator_id = operatorId;
enrichedProject.meta.vat_number = ownerData.vat_number;
enrichedProject.meta.status = "draft";

// Aggiungi validità preventivo (+30 giorni)
const validUntil = new Date();
validUntil.setDate(validUntil.getDate() + 30);
enrichedProject.meta.valid_until = validUntil.toISOString().split('T')[0];

// === 7. AGGIORNA CUSTOMER CONTEXT CON DATI REALI ===
enrichedProject.customer_context = {
  name: realCustomerData.company !== "Privato" ? 
    `${realCustomerData.name} (${realCustomerData.company})` : 
    realCustomerData.name,
  email: realCustomerData.email,
  phone: realCustomerData.phone,
  address: realCustomerData.address,
  needs_summary: enrichedProject.customer_context.needs_summary
};

// === 8. AGGIORNA TASK NEL CUSTOMER CON PROJECT DRAFT ===
const updatedCustomer = JSON.parse(JSON.stringify(customer));

if (taskIndex !== -1 && taskIndex !== undefined) {
  // Aggiungi il project al task corrispondente
  updatedCustomer.tasks[taskIndex].project = {
    project_id: projectId,
    quote_id: enrichedProject.meta.quote_id,
    status: "draft",
    created_at: enrichedProject.meta.created_at,
    total_amount: enrichedProject.financials.grand_total,
    currency: enrichedProject.financials.currency
  };

  console.log(`✅ Task aggiornato con project_id: ${projectId} (status: draft)`);
} else {
  console.warn('⚠️ Nessun task trovato per aggiornare il project');
}

// === 9. OUTPUT FINALE ===
const output = {
  owner_data: ownerData,
  operator_id: operatorId,
  operator_name: operatorName,
  operator_note: item.OperatorNote,

  // Customer aggiornato con project nel task
  customer: updatedCustomer,

  // Project arricchito e con placeholder sostituiti
  project: enrichedProject,

  // Metadati per workflow successivi
  workflow_metadata: {
    project_id: projectId,
    invite_token: inviteToken,
    customer_email: realCustomerData.email,
    total_amount: enrichedProject.financials.grand_total,
    currency: enrichedProject.financials.currency,
    status: "draft",
    created_at: enrichedProject.meta.created_at,
    valid_until: enrichedProject.meta.valid_until
  }
};

// Logging
console.log(`✅ Project ID: ${projectId}`);
console.log(`👤 Operatore: ${operatorName}`);
console.log(`📧 Cliente: ${realCustomerData.name} (${realCustomerData.email})`);
console.log(`💰 Totale: ${enrichedProject.financials.grand_total} ${enrichedProject.financials.currency}`);
console.log(`🔗 Invite Token: ${inviteToken || 'N/A'}`);
console.log(`📊 Status: draft`);

return [{ json: output }];

// Recuperiamo i dati dal nodo precedente
const inputData = items[0].json.body ? items[0].json.body.project : items[0].json;

// --- FUNZIONI DI UTILITÀ ---

const formatMoney = (amount, currency = 'EUR') => {
  return new Intl.NumberFormat('it-IT', {
    style: 'currency',
    currency: currency,
    minimumFractionDigits: 2
  }).format(amount);
};

const formatDate = (dateString) => {
  if (!dateString) return '';
  const date = new Date(dateString);
  return date.toLocaleDateString('it-IT', { day: '2-digit', month: '2-digit', year: 'numeric' });
};

// --- LOGICA FISCALE ---
let taxNote = "";
if (inputData.financials.tax_amount === 0) {
    taxNote = "Operazione effettuata ai sensi dell’articolo 1, commi da 54 a 89, della Legge n. 190/2014 così come modificato dalla Legge n. 208/2015. Imposta di bollo da 2 euro assolta sull'originale per importi superiori a 77,47 euro.";
}

// --- COSTRUZIONE HTML ---

const itemsHtml = inputData.items.map(item => {

    const complianceBadges = (item.compliance_trust_badges || []).map(badge => 
        `<span class="badge-trust">🛡️ ${badge}</span>`
    ).join('');

    const milestonesList = (item.milestones || []).map(m => 
        `<li class="milestone-item"><span class="icon-check">✓</span> ${m}</li>`
    ).join('');

    return `
    <div class="service-card">
        <div class="card-header">
            <div class="header-left">
                <span class="service-name">${item.name}</span>
                <span class="sku-tag">${item.sku}</span>
            </div>
            <div class="header-right">
                <span class="service-price">${formatMoney(item.total, inputData.financials.currency)}</span>
            </div>
        </div>

        <div class="card-body">
            <div class="timeline-pill">⏱ ${item.timeline_estimation}</div>

            <div class="description">
                ${item.description_customized}
            </div>

            <div class="compliance-section">
                ${complianceBadges}
            </div>

            <div class="milestones-section">
                <h5>Fasi Operative</h5>
                <ul>
                    ${milestonesList}
                </ul>
            </div>
        </div>
    </div>
    `;
}).join('');


// --- TEMPLATE COMPLETO ---
const htmlTemplate = `
<!DOCTYPE html>
<html lang="${inputData.meta.language || 'it'}">
<head>
    <meta charset="UTF-8">
    <title>Preventivo ${inputData.meta.quote_id}</title>
