        }

        .brand h1 { margin: 0; color: var(--secondary); font-size: 24px; text-transform: uppercase; font-weight: 800; line-height: 1.2; }

        .provider-details {
            font-size: 13px;
            color: #475569;
            margin-top: 4px;
            margin-bottom: 8px;
        }

        .doc-type {
            font-size: 11px;
            color: var(--primary);
            font-weight: 700;
            letter-spacing: 1px;
            text-transform: uppercase;
            background: var(--primary-light);
            padding: 4px 8px;
            border-radius: 4px;
            display: inline-block;
        }

        .meta-grid { text-align: right; font-size: 13px; color: #64748B; }
        .meta-grid strong { color: var(--secondary); }

        /* CLIENT INFO */
        .info-section {
            display: grid;
            grid-template-columns: 1fr 1fr;
            gap: 40px;
            margin-bottom: 40px;
        }

        .info-box h3 { font-size: 11px; text-transform: uppercase; color: #94A3B8; border-bottom: 1px solid var(--border); padding-bottom: 8px; margin-bottom: 10px; }
        .client-name { font-size: 18px; font-weight: 700; color: var(--secondary); }
        .client-details { font-size: 13px; color: #475569; margin-top: 5px; }

        /* EXECUTIVE SUMMARY */
        .exec-summary {
            background: linear-gradient(135deg, var(--primary-light) 0%, #FFFFFF 100%);
            border: 1px solid #BFDBFE;
            border-left: 5px solid var(--primary);
            border-radius: 8px;
            padding: 25px;
            margin-bottom: 50px;
        }
        .exec-title { color: var(--primary); font-weight: 700; font-size: 18px; margin-bottom: 10px; }
        .exec-text { font-size: 15px; color: var(--secondary); margin: 0; }

        /* SERVICE CARDS */
        .service-card {
            border: 1px solid var(--border);
            border-radius: 12px;
            margin-bottom: 30px;
            overflow: hidden;
            page-break-inside: avoid;
            box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.05);
        }

        .card-header {
            background: #F8FAFC;
            padding: 20px 25px;
            display: flex;
            justify-content: space-between;
            align-items: center;
            border-bottom: 1px solid var(--border);
        }

        .service-name { font-weight: 700; color: var(--secondary); font-size: 16px; display: block; }
        .sku-tag { font-family: monospace; font-size: 11px; background: #E2E8F0; padding: 2px 6px; border-radius: 4px; color: #64748B; margin-top: 4px; display: inline-block; }
        .service-price { font-weight: 700; font-size: 18px; color: var(--secondary); }

        .card-body { padding: 25px; }

        .timeline-pill {
            display: inline-block;
            background: var(--warning-bg);
            color: var(--warning-text);
            font-size: 12px;
            font-weight: 600;
            padding: 4px 12px;
            border-radius: 20px;
            margin-bottom: 15px;
            border: 1px solid #FDE68A;
        }

        .description { font-size: 14px; margin-bottom: 25px; text-align: justify; }

        .compliance-section { display: flex; flex-wrap: wrap; gap: 8px; margin-bottom: 25px; }
        .badge-trust { 
            font-size: 11px; background: var(--success-bg); color: var(--success); 
            padding: 4px 8px; border-radius: 4px; font-weight: 600; border: 1px solid #A7F3D0; 
        }

        .milestones-section { background: #F8FAFC; padding: 15px; border-radius: 8px; }
        .milestones-section h5 { margin: 0 0 10px 0; font-size: 11px; text-transform: uppercase; color: #94A3B8; }
        .milestones-section ul { padding: 0; margin: 0; list-style: none; }
        .milestone-item { font-size: 13px; margin-bottom: 6px; display: flex; gap: 10px; }
        .icon-check { color: var(--primary); font-weight: bold; }

        /* FINANCIALS */
        .financials-wrapper {
            display: flex;
            justify-content: flex-end;
            margin-top: 40px;
            page-break-inside: avoid;
        }

        .totals-table { width: 350px; border-collapse: collapse; }
        .totals-table td { padding: 8px 0; text-align: right; }
        .label { font-size: 14px; color: #64748B; }
        .value { font-size: 15px; font-weight: 600; color: var(--secondary); font-family: monospace; }

        .grand-total td { border-top: 2px solid var(--secondary); padding-top: 15px; margin-top: 10px; }
        .grand-total .label { font-weight: 700; color: var(--secondary); font-size: 16px; }
        .grand-total .value { font-weight: 800; color: var(--primary); font-size: 24px; }

        /* FOOTER */
        footer {
            margin-top: 60px;
            border-top: 1px solid var(--border);
            padding-top: 20px;
            font-size: 11px;
            color: #94A3B8;
            text-align: center;
        }
        .tax-note { color: #64748B; font-style: italic; margin-top: 5px; }

    </style>
</head>
<body>

<div class="container">

    <header>
        <div class="brand">
            <h1>${inputData.meta.provider_name}</h1>
            <div class="provider-details">
                P.IVA: ${inputData.meta.vat_number || 'N/A'}
            </div>
            <span class="doc-type">Project Proposal</span>
        </div>
        <div class="meta-grid">
            <div><strong>ID Progetto:</strong> ${inputData.meta.quote_id}</div>
            <div><strong>Emesso il:</strong> ${formatDate(inputData.meta.created_at)}</div>
            <div><strong>Scadenza:</strong> ${formatDate(inputData.meta.valid_until)}</div>
        </div>
    </header>

    <div class="info-section">
        <div class="info-box">
            <h3>Destinatario</h3>
            <div class="client-name">${inputData.customer_context.name}</div>
            <div class="client-details">
                ${inputData.customer_context.address ? inputData.customer_context.address + '<br>' : ''}
                ${inputData.customer_context.email}<br>
                ${inputData.customer_context.phone || ''}
            </div>
        </div>
        <div class="info-box">
            <h3>Obiettivo Strategico</h3>
            <div style="font-size: 14px; color: #475569; font-style: italic;">
                "${inputData.customer_context.needs_summary}"
            </div>
        </div>
    </div>

    <div class="exec-summary">
        <div class="exec-title">${inputData.executive_summary.title}</div>
        <p class="exec-text">${inputData.executive_summary.value_proposition}</p>
    </div>

    <div class="services-list">
        ${itemsHtml}
    </div>

    <div class="financials-wrapper">
        <table class="totals-table">
            <tr>
                <td class="label">Imponibile</td>
                <td class="value">${formatMoney(inputData.financials.subtotal, inputData.financials.currency)}</td>
            </tr>
            ${inputData.financials.tax_amount > 0 ? `
            <tr>
                <td class="label">IVA (${inputData.financials.tax_percent}%)</td>
                <td class="value">${formatMoney(inputData.financials.tax_amount, inputData.financials.currency)}</td>
            </tr>` : ''}

            <tr class="grand-total">
                <td class="label">TOTALE</td>
                <td class="value">${formatMoney(inputData.financials.grand_total, inputData.financials.currency)}</td>
            </tr>
        </table>
    </div>

    <footer>
        <div>${inputData.meta.provider_name} • P.IVA ${inputData.meta.vat_number}</div>
        <div class="tax-note">${taxNote}</div>
    </footer>

</div>

</body>
</html>
`;

return {
  html: htmlTemplate
};

